dark.canvasScript:
/**
 * Title: Gaseous Nebula Flow
 * Description: Billowing cosmic gas clouds that react to the mouse like gravitational fluid.
 */

const CONFIG = {
    cloudCount: 6,
    baseColors: [
        'rgba(30, 50, 150, 0.12)',
        'rgba(80, 40, 120, 0.1)',
        'rgba(20, 100, 140, 0.08)',
        'rgba(10, 20, 60, 0.15)'
    ],
    mouseGravity: 0.02
};

let canvas, ctx, w, h;
let clouds = [];
let mouse = { x: -5000, y: -5000 };

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    } else if (e.data.type === 'mousemove') {
        mouse.x = e.data.x; mouse.y = e.data.y;
    }
};

function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
    clouds = [];
    for (let i = 0; i < CONFIG.cloudCount; i++) {
        clouds.push({
            x: Math.random() * w,
            y: Math.random() * h,
            r: Math.random() * (w * 0.8) + (w * 0.4),
            vx: (Math.random() - 0.5) * 1.5,
            vy: (Math.random() - 0.5) * 1.5,
            color: CONFIG.baseColors[i % CONFIG.baseColors.length]
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, w, h);
    ctx.globalCompositeOperation = 'screen';

    for (let c of clouds) {
        // Mouse Interaction: Gravity
        let dx = mouse.x - c.x;
        let dy = mouse.y - c.y;
        let dist = Math.hypot(dx, dy);

        if (dist < 1000) {
            c.vx += (dx / dist) * CONFIG.mouseGravity;
            c.vy += (dy / dist) * CONFIG.mouseGravity;
        }

        c.x += c.vx;
        c.y += c.vy;
        c.vx *= 0.99; // Damping
        c.vy *= 0.99;

        // Screen Wrap with large padding for clouds
        if (c.x < -c.r) c.x = w + c.r;
        if (c.x > w + c.r) c.x = -c.r;
        if (c.y < -c.r) c.y = h + c.r;
        if (c.y > h + c.r) c.y = -c.r;

        let grad = ctx.createRadialGradient(c.x, c.y, 0, c.x, c.y, c.r);
        grad.addColorStop(0, c.color);
        grad.addColorStop(0.5, c.color.replace('0.1', '0.05'));
        grad.addColorStop(1, 'rgba(0,0,0,0)');

        ctx.fillStyle = grad;
        ctx.beginPath();
        ctx.arc(c.x, c.y, c.r, 0, Math.PI * 2);
        ctx.fill();
    }

    requestAnimationFrame(render);
}

