dark.canvasScript:
/**
 * Title: Geometric Mainframe
 * Description: Rotating amber wireframe polygons that drift like data fragments.
 */

const CONFIG = {
    shardCount: 15,
    color: 'rgba(255, 176, 0, 0.2)',
    rotationSpeed: 0.005,
    driftSpeed: 0.3
};

let canvas, ctx, w, h;
let shards = [];

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    }
};

function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
    shards = [];
    for (let i = 0; i < CONFIG.shardCount; i++) {
        shards.push({
            x: Math.random() * w,
            y: Math.random() * h,
            size: Math.random() * 80 + 40,
            angle: Math.random() * Math.PI * 2,
            rot: (Math.random() - 0.5) * 0.02,
            vx: (Math.random() - 0.5) * CONFIG.driftSpeed,
            vy: (Math.random() - 0.5) * CONFIG.driftSpeed,
            sides: Math.floor(Math.random() * 3) + 3 // 3 to 5 sides
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, w, h);
    ctx.strokeStyle = CONFIG.color;
    ctx.lineWidth = 1;

    for (let s of shards) {
        s.x += s.vx; s.y += s.vy;
        s.angle += s.rot;

        if (s.x < -100) s.x = w + 100; if (s.x > w + 100) s.x = -100;
        if (s.y < -100) s.y = h + 100; if (s.y > h + 100) s.y = -100;

        ctx.beginPath();
        for (let i = 0; i < s.sides; i++) {
            let x = s.x + Math.cos(s.angle + (i * Math.PI * 2) / s.sides) * s.size;
            let y = s.y + Math.sin(s.angle + (i * Math.PI * 2) / s.sides) * s.size;
            if (i === 0) ctx.moveTo(x, y); else ctx.lineTo(x, y);
        }
        ctx.closePath();
        ctx.stroke();
    }
    requestAnimationFrame(render);
}

