                ctx.strokeStyle = CONFIG.linkColor;
                ctx.lineWidth = 1;
                ctx.moveTo(p.x, p.y);
                ctx.lineTo(p2.x, p2.y);
                ctx.stroke();
            }
        }

        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(255, 0, 0, ${p.opacity})`;
        ctx.fill();
    }

    requestAnimationFrame(render);
}

