dark.canvasScript:
/**
 * Title: Fireflies (Emerald Canopy)
 * Description: Bioluminescent forest spores drifting lazily.
 */
let canvas, ctx, w, h;
let particles = [];

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    }
};

function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
    particles = [];
    for (let i = 0; i < 25; i++) {
        particles.push({
            x: Math.random() * w, y: Math.random() * h,
            vx: (Math.random() - 0.5) * 0.4,
            vy: (Math.random() - 0.5) * 0.4,
            r: Math.random() * 3 + 1,
            alpha: Math.random(),
            speed: 0.01 + Math.random() * 0.02
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, w, h);
    for (let p of particles) {
        p.x += p.vx;
        p.y += p.vy;
        p.alpha += p.speed;
        if (p.alpha > 1 || p.alpha < 0) p.speed = -p.speed;
        if (p.x < 0) p.x = w; if (p.x > w) p.x = 0;
        if (p.y < 0) p.y = h; if (p.y > h) p.y = 0;

        ctx.beginPath();
        ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(46, 204, 113, ${Math.abs(p.alpha)})`;
        ctx.shadowBlur = 10;
        ctx.shadowColor = '#2ecc71';
        ctx.fill();
    }
    ctx.shadowBlur = 0; // Reset
    requestAnimationFrame(render);
}

light.canvasScript:
/**
 * Title: Wind Currents (Stratosphere)
 * Description: Graceful white currents drifting across the screen.
 */
let canvas, ctx, w, h;
let lines = [];

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    }
};

function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
    lines = [];
    for (let i = 0; i < 5; i++) {
        lines.push({
            y: Math.random() * h,
            length: Math.random() * 200 + 150,
            speed: Math.random() * 0.5 + 0.2,
            opacity: Math.random() * 0.3 + 0.1
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, w, h);
    ctx.lineWidth = 1.5;
    for (let l of lines) {
        l.y += Math.sin(l.y * 0.01) * 0.1; // Gentle sway
        ctx.strokeStyle = `rgba(255, 255, 255, ${l.opacity})`;
        ctx.beginPath();
        ctx.moveTo(0, l.y);
        ctx.quadraticCurveTo(w / 2, l.y + 40, w, l.y);
        ctx.stroke();
    }
    requestAnimationFrame(render);
}

oled.canvasScript:
/**
 * Title: Starfield Warp (Cosmic Horizon)
 * Description: Classic 2D warp-speed star travel.
 */
let canvas, ctx, w, h;
let stars = [];

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    }
};

function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
    stars = [];
    for (let i = 0; i < 100; i++) {
        stars.push({
            x: Math.random() * w - w/2,
            y: Math.random() * h - h/2,
            z: Math.random() * w
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.fillStyle = 'rgba(0, 0, 0, 0.25)';
    ctx.fillRect(0, 0, w, h);

    ctx.fillStyle = '#ffffff';
    for (let s of stars) {
        s.z -= 1.5;
        if (s.z <= 0) s.z = w;
        let px = (s.x / s.z) * (w / 2) + w/2;
        let py = (s.y / s.z) * (h / 2) + h/2;
        if (px < 0 || px > w || py < 0 || py > h) s.z = w;
        let size = (1 - s.z / w) * 3;
        ctx.fillRect(px, py, size, size);
    }
    requestAnimationFrame(render);
}

her.canvasScript:
/**
 * Title: Sakura Blossom Fall (Sakura Breeze)
 * Description: Delicate cherry blossom petals falling with gravity.
 */
let canvas, ctx, w, h;
let petals = [];

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    }
};

function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
    petals = [];
    for (let i = 0; i < 30; i++) {
        petals.push({
            x: Math.random() * w,
            y: Math.random() * h - h,
            r: Math.random() * 4 + 2,
            d: Math.random() * w,
            speed: Math.random() * 1.5 + 0.8,
            sway: Math.random() * 2
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, w, h);
    ctx.fillStyle = 'rgba(255, 179, 209, 0.7)';
    for (let p of petals) {
        p.y += p.speed;
        p.x += Math.sin(p.y / 30) * p.sway * 0.5;
        if (p.y > h) {
            p.y = -20;
            p.x = Math.random() * w;
        }
        ctx.beginPath();
        ctx.ellipse(p.x, p.y, p.r, p.r * 1.5, Math.PI / 4, 0, Math.PI * 2);
        ctx.fill();
    }
    requestAnimationFrame(render);
}

