/* --- SIDEBAR - Off-Angle Implementation --- */
#sidebar, .sidebar, [data-testid="sidebar"] {
  /* Base styling */
  background: var(--persona-surface) !important;
  border-right: 3px solid var(--persona-primary) !important;

  /* Persona off-angle effect */
