    for (let i = 0; i < CONFIG.particleCount; i++) {
        particles.push({
            x: Math.random() * width,
            y: Math.random() * height,
            vx: (Math.random() - 0.5) * 0.3,
            vy: -(Math.random() * CONFIG.driftSpeed + 0.1),
